// Best-effort proof. The obligation requires showing
    //   post1_self_ == post2_self_
    // (struct equality) from the antecedent which only constrains the
    // views (Seq<K>) and `valid()` predicate. StrictlyOrderedVec has a
    // single private field `v: Vec<K>`. Verus's `Vec<T>` does not have a
    // view-injectivity axiom (`v1@ == v2@ ==> v1 == v2`), so we cannot
    // conclude struct equality from view equality alone. We document the
    // partial result we *can* derive.
    if post1_self_.valid()
        && post1_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int)
        && pre_self_@.to_set() == post1_self_@.to_set() + pre_self_@.subrange(start as int, end as int).to_set()
        && post2_self_.valid()
        && post2_self_@ == pre_self_@.subrange(0, start as int) + pre_self_@.subrange(end as int, pre_self_@.len() as int)
        && pre_self_@.to_set() == post2_self_@.to_set() + pre_self_@.subrange(start as int, end as int).to_set()
    {
        assert(post1_self_@ == post2_self_@);
        assert(post1_self_.v@ == post2_self_.v@);
    }
